    @Test
    void exitCodeNonZero() throws Exception {
        E2bEnvdProcessClient client = new E2bEnvdProcessClient(options(E2bCodec.JSON));
        byte[] frame = concatFrames(connectFrame(endEventJson(42, null)), endStreamFrame("{}"));
