   187 |             // Connect protocol: flags bit 1 = end_stream — final envelope carries EndStreamMessage
   188 |             // JSON
   189 |             // https://connectrpc.com/docs/protocol/#streaming-rpcs
   190 |             if ((flags & 0x02) != 0) {
   191 |                 EndStreamMessage endMsg = parseEndStreamResponse(data);
   192 |                 if (endMsg.hasError()) {
   193 |                     log.debug(
   194 |                             "drainStartStream: endStream error code={} msg={}",
   195 |                             endMsg.code(),
   196 |                             endMsg.message());
   197 |                     throw new SandboxException.SandboxRuntimeException(
   198 |                             SandboxErrorCode.WORKSPACE_START_ERROR,
   199 |                             "Process start failed: " + endMsg.code() + ": " + endMsg.message());
   200 |                 }
   201 |                 log.debug("drainStartStream: endStream ok, exit={}", exit);
   202 |                 break;
   203 |             }
   204 |             // Connect protocol: flags bit 0 = compressed
   205 |             // https://connectrpc.com/docs/protocol/#streaming-rpcs
   206 |             if ((flags & 0x01) != 0) {
   207 |                 throw new IOException("Compressed connect frames not supported");
   208 |             }
   209 |             // Connect protocol: flags bits 2-7 reserved for future extensions
   210 |             // https://connectrpc.com/docs/protocol/#streaming-rpcs
   211 |             if ((flags & 0xFC) != 0) {
   212 |                 continue;
   213 |             }
   214 |             try {
   215 |                 DynamicMessage sr = parseStartResponseFrame(data);
   216 |                 if (!sr.hasField(srEventF)) {
   217 |                     log.debug("drainStartStream: frame with no event");
   218 |                     continue;
   219 |                 }
   220 |                 DynamicMessage pe = (DynamicMessage) sr.getField(srEventF);
   221 |                 if (pe.hasField(peDataF)) {
   222 |                     DynamicMessage de = (DynamicMessage) pe.getField(peDataF);
   223 |                     appendDataStream(de, "stdout", stdout);
   224 |                     appendDataStream(de, "stderr", stderr);
   225 |                 }
   226 |                 if (pe.hasField(peEndF)) {
   227 |                     DynamicMessage end = (DynamicMessage) pe.getField(peEndF);
   228 |                     Descriptors.Descriptor endDesc = end.getDescriptorForType();
   229 |                     // Proto3: scalar sint32 defaults to 0, omitted from wire when 0.
   230 |                     // getField() returns proto3 default (0) when absent; hasField() returns false.
   231 |                     // https://protobuf.dev/programming-guides/proto3/#default
   232 |                     Descriptors.FieldDescriptor ecF = endDesc.findFieldByName("exit_code");
   233 |                     Object v = end.getField(ecF);
   234 |                     exit = v instanceof Integer ? (Integer) v : ((Long) v).intValue();
   235 |                     // EndEvent.error — populated when cmd.Wait() returns ExitError
   236 |                     // (non-zero exit code or signal). Go handler: ProcessEvent_EndEvent.Error =
   237 |                     // errMsg
   238 |                     // https://github.com/e2b-dev/infra/blob/main/packages/envd/internal/services/process/handler/handler.go
   239 |                     // Python SDK: error=event.event.end.error
   240 |                     // https://github.com/e2b-dev/e2b/blob/main/packages/python-sdk/e2b/sandbox_sync/commands/command_handle.py#L115
   241 |                     Descriptors.FieldDescriptor errF = endDesc.findFieldByName("error");
   242 |                     if (end.hasField(errF)) {
   243 |                         stderr.write(
   244 |                                 String.valueOf(end.getField(errF))
   245 |                                         .getBytes(StandardCharsets.UTF_8));
   246 |                     }
   247 |                 }
   248 |             } catch (IOException ignored) {
   249 |             }
   250 |         }
   251 |         return exit;
   252 |     }
