   254 |     private static void appendDataStream(
   255 |             DynamicMessage dataEv, String field, ByteArrayOutputStream out) throws IOException {
   256 |         for (Map.Entry<Descriptors.FieldDescriptor, Object> entry :
   257 |                 dataEv.getAllFields().entrySet()) {
   258 |             if (!field.equals(entry.getKey().getName())) {
   259 |                 continue;
   260 |             }
   261 |             Object v = entry.getValue();
   262 |             if (v instanceof ByteString) {
   263 |                 ((ByteString) v).writeTo(out);
   264 |             }
   265 |             return;
   266 |         }
   267 |     }
