   269 |     // Connect protocol EndStreamMessage JSON: {"error":{"code":"...","message":"..."}}
   270 |     // Python SDK ServerStreamParser also parses end_stream envelope as JSON error:
   271 |     //   if EnvelopeFlags.end_stream in flags:
   272 |     //       data = json.loads(data)
   273 |     //       if "error" in data: raise make_error(data["error"])
   274 |     //       return  # no error → stop iteration
   275 |     // https://connectrpc.com/docs/protocol/#error-end-stream
   276 |     // https://github.com/e2b-dev/e2b/blob/main/packages/python-sdk/e2b_connect/client.py#L230-L238
   277 |     private static EndStreamMessage parseEndStreamResponse(byte[] data) throws IOException {
   278 |         JsonNode root = JSON.readTree(data);
   279 |         if (root == null || root.isNull()) {
   280 |             return new EndStreamMessage(null, null);
   281 |         }
   282 |         JsonNode errorNode = root.path("error");
   283 |         if (errorNode.isMissingNode() || errorNode.isNull()) {
   284 |             return new EndStreamMessage(null, null);
   285 |         }
   286 |         String code = errorNode.path("code").asText(null);
   287 |         String message = errorNode.path("message").asText(null);
   288 |         return new EndStreamMessage(code, message);
   289 |     }
