   299 |         DynamicMessage.Builder pcb = DynamicMessage.newBuilder(pcDesc);
   300 |         pcb.setField(pcDesc.findFieldByName("cmd"), "/bin/bash");
   301 |         pcb.addRepeatedField(pcDesc.findFieldByName("args"), "-l");
   302 |         pcb.addRepeatedField(pcDesc.findFieldByName("args"), "-c");
   303 |         pcb.addRepeatedField(pcDesc.findFieldByName("args"), shellCommand);
   304 |         if (cwd != null && !cwd.isBlank()) {
   305 |             pcb.setField(pcDesc.findFieldByName("cwd"), cwd);
