   341 |     static byte[] encodeUnaryEnvelope(byte[] msg) {
   342 |         byte[] out = new byte[5 + msg.length];
   343 |         out[0] = 0x00;
   344 |         ByteBuffer.wrap(out, 1, 4).order(ByteOrder.BIG_ENDIAN).putInt(msg.length);
   345 |         System.arraycopy(msg, 0, out, 5, msg.length);
   346 |         return out;
