   448 |     private byte[] encodeJsonStartRequest(DynamicMessage msg) throws IOException {
   449 |         Descriptors.FieldDescriptor processField = startRequestDesc.findFieldByName("process");
   450 |         Descriptors.FieldDescriptor stdinField = startRequestDesc.findFieldByName("stdin");
   451 |         DynamicMessage process = (DynamicMessage) msg.getField(processField);
   452 |         Descriptors.Descriptor processDesc = process.getDescriptorForType();
   453 | 
   454 |         ObjectNode root = JSON.createObjectNode();
   455 |         ObjectNode processNode = root.putObject("process");
   456 |         processNode.put(
   457 |                 "cmd", stringField(process, processDesc.findFieldByName("cmd"), "/bin/bash"));
   458 |         ArrayNode argsNode = processNode.putArray("args");
   459 |         Descriptors.FieldDescriptor argsField = processDesc.findFieldByName("args");
   460 |         @SuppressWarnings("unchecked")
   461 |         java.util.List<Object> args = (java.util.List<Object>) process.getField(argsField);
   462 |         for (Object arg : args) {
   463 |             argsNode.add(String.valueOf(arg));
   464 |         }
   465 |         Descriptors.FieldDescriptor cwdField = processDesc.findFieldByName("cwd");
   466 |         if (process.hasField(cwdField)) {
   467 |             processNode.put("cwd", String.valueOf(process.getField(cwdField)));
   468 |         }
   469 |         root.put(
   470 |                 "stdin", msg.hasField(stdinField) && Boolean.TRUE.equals(msg.getField(stdinField)));
