   474 |     private DynamicMessage parseJsonStartResponse(byte[] data) throws IOException {
   475 |         JsonNode root = JSON.readTree(data);
   476 |         if (root == null || root.isNull()) {
   477 |             return DynamicMessage.newBuilder(startResponseDesc).build();
   478 |         }
   479 |         DynamicMessage.Builder response = DynamicMessage.newBuilder(startResponseDesc);
   480 |         JsonNode eventNode = root.path("event");
   481 |         if (eventNode.isMissingNode() || eventNode.isNull()) {
   482 |             return response.build();
   483 |         }
   484 |         DynamicMessage.Builder event = DynamicMessage.newBuilder(processEventDesc);
   485 | 
   486 |         JsonNode dataNode = eventNode.path("data");
   487 |         if (!dataNode.isMissingNode() && !dataNode.isNull()) {
   488 |             Descriptors.Descriptor dataDesc = processEventDesc.findNestedTypeByName("DataEvent");
   489 |             DynamicMessage.Builder dataBuilder = DynamicMessage.newBuilder(dataDesc);
   490 |             setBytesIfPresent(dataBuilder, dataNode, "stdout", dataDesc.findFieldByName("stdout"));
   491 |             setBytesIfPresent(dataBuilder, dataNode, "stderr", dataDesc.findFieldByName("stderr"));
   492 |             if (!dataBuilder.getAllFields().isEmpty()) {
   493 |                 event.setField(processEventDesc.findFieldByName("data"), dataBuilder.build());
   494 |             }
   495 |         }
   496 | 
   497 |         JsonNode endNode = eventNode.path("end");
   498 |         if (!endNode.isMissingNode() && !endNode.isNull()) {
   499 |             // Always set end on event when node exists, even if sub-fields are empty
   500 |             // (proto3 default 0 for sint32, empty string for proto3_optional).
   501 |             // Also parse "error" field for signal-killed processes.
   502 |             // Python SDK reads exit_code/error directly without presence check:
   503 |             //   exit_code=event.event.end.exit_code, error=event.event.end.error
   504 |             // https://github.com/e2b-dev/e2b/blob/main/packages/python-sdk/e2b/sandbox_sync/commands/command_handle.py#L115
   505 |             Descriptors.Descriptor endDesc = processEventDesc.findNestedTypeByName("EndEvent");
   506 |             DynamicMessage.Builder endBuilder = DynamicMessage.newBuilder(endDesc);
   507 |             Descriptors.FieldDescriptor exitCodeField = endDesc.findFieldByName("exit_code");
   508 |             JsonNode exitCodeNode = endNode.path("exitCode");
   509 |             if (exitCodeNode.canConvertToInt()) {
   510 |                 endBuilder.setField(exitCodeField, exitCodeNode.intValue());
   511 |             }
   512 |             Descriptors.FieldDescriptor errorField = endDesc.findFieldByName("error");
   513 |             // EndEvent.error — populated when cmd.Wait() returns ExitError
   514 |             // (non-zero exit code or signal). Go handler: Error = errMsg.
   515 |             // https://github.com/e2b-dev/infra/blob/main/packages/envd/internal/services/process/handler/handler.go
   516 |             // Python SDK: error=event.event.end.error
   517 |             // https://github.com/e2b-dev/e2b/blob/main/packages/python-sdk/e2b/sandbox_sync/commands/command_handle.py#L115
   518 |             JsonNode errorNode = endNode.path("error");
   519 |             if (errorNode.isTextual()) {
   520 |                 endBuilder.setField(errorField, errorNode.textValue());
   521 |             }
   522 |             event.setField(processEventDesc.findFieldByName("end"), endBuilder.build());
   523 |         }
   524 | 
   525 |         if (!event.getAllFields().isEmpty()) {
   526 |             response.setField(startResponseDesc.findFieldByName("event"), event.build());
   527 |         }
   528 |         return response.build();
   529 |     }
