   531 |     private static void setBytesIfPresent(
   532 |             DynamicMessage.Builder builder,
   533 |             JsonNode parent,
   534 |             String jsonField,
   535 |             Descriptors.FieldDescriptor field) {
   536 |         JsonNode valueNode = parent.path(jsonField);
   537 |         if (valueNode.isTextual()) {
   538 |             try {
   539 |                 builder.setField(
   540 |                         field,
   541 |                         ByteString.copyFrom(Base64.getDecoder().decode(valueNode.textValue())));
   542 |             } catch (IllegalArgumentException ignored) {
   543 |                 // Malformed base64 from the server should not abort the stream.
   544 |             }
   545 |         }
   546 |     }
   547 | 
   548 |     private static String stringField(
   549 |             DynamicMessage message, Descriptors.FieldDescriptor field, String defaultValue) {
   550 |         if (field == null || !message.hasField(field)) {
   551 |             return defaultValue;
   552 |         }
   553 |         return String.valueOf(message.getField(field));
   554 |     }
   555 | 
   556 |     private static String envdHost(E2bSandboxState state) {
   557 |         String id = state.getSandboxId();
   558 |         String dom =
   559 |                 state.getSandboxDomain() != null && !state.getSandboxDomain().isBlank()
   560 |                         ? state.getSandboxDomain()
   561 |                         : "e2b.app";
   562 |         return "https://" + ENVD_PORT + "-" + id + "." + dom;
   563 |     }
   564 | 
   565 |     private static String basicAuthUser(String user) {
   566 |         String u = user != null ? user : "user";
   567 |         String token =
   568 |                 Base64.getEncoder().encodeToString((u + ":").getBytes(StandardCharsets.UTF_8));
   569 |         return "Basic " + token;
   570 |     }
   571 | 
   572 |     private static String truncateUtf8(byte[] b) {
   573 |         int n = Math.min(b.length, OUTPUT_TRUNCATE_BYTES);
   574 |         return new String(b, 0, n, StandardCharsets.UTF_8);
   575 |     }
   576 | }


