   156 |     private static DynamicMessage dataResponse(
   157 |             E2bEnvdProcessClient client, String stdout, String stderr) {
   158 |         Descriptors.FileDescriptor fd = client.fileDescriptor();
   159 |         Descriptors.Descriptor processEventDesc = fd.findMessageTypeByName("ProcessEvent");
   160 |         Descriptors.Descriptor dataDesc = processEventDesc.findNestedTypeByName("DataEvent");
   161 | 
   162 |         DynamicMessage data =
   163 |                 DynamicMessage.newBuilder(dataDesc)
   164 |                         .setField(
   165 |                                 stdout != null
   166 |                                         ? dataDesc.findFieldByName("stdout")
   167 |                                         : dataDesc.findFieldByName("stderr"),
   168 |                                 ByteString.copyFromUtf8(stdout != null ? stdout : stderr))
   169 |                         .build();
   170 |         DynamicMessage event =
   171 |                 DynamicMessage.newBuilder(processEventDesc)
   172 |                         .setField(processEventDesc.findFieldByName("data"), data)
   173 |                         .build();
   174 |         Descriptors.Descriptor startResponseDesc = fd.findMessageTypeByName("StartResponse");
   175 |         return DynamicMessage.newBuilder(startResponseDesc)
   176 |                 .setField(startResponseDesc.findFieldByName("event"), event)
   177 |                 .build();
   178 |     }
   179 | 
   180 |     private static DynamicMessage endEventResponse(
   181 |             E2bEnvdProcessClient client, Integer exitCode, String error) {
   182 |         Descriptors.FileDescriptor fd = client.fileDescriptor();
   183 |         Descriptors.Descriptor processEventDesc = fd.findMessageTypeByName("ProcessEvent");
   184 |         Descriptors.Descriptor endDesc = processEventDesc.findNestedTypeByName("EndEvent");
   185 | 
   186 |         DynamicMessage.Builder endBuilder = DynamicMessage.newBuilder(endDesc);
   187 |         if (exitCode != null) {
   188 |             endBuilder.setField(endDesc.findFieldByName("exit_code"), exitCode);
   189 |         }
   190 |         if (error != null) {
   191 |             endBuilder.setField(endDesc.findFieldByName("error"), error);
   192 |         }
   193 |         DynamicMessage end = endBuilder.build();
   194 | 
   195 |         DynamicMessage event =
   196 |                 DynamicMessage.newBuilder(processEventDesc)
   197 |                         .setField(processEventDesc.findFieldByName("end"), end)
   198 |                         .build();
   199 |         Descriptors.Descriptor startResponseDesc = fd.findMessageTypeByName("StartResponse");
   200 |         return DynamicMessage.newBuilder(startResponseDesc)
   201 |                 .setField(startResponseDesc.findFieldByName("event"), event)
   202 |                 .build();
   203 |     }
