   460 |     private static int drainStartStream(
   461 |             E2bEnvdProcessClient client,
   462 |             byte[] connectFrame,
   463 |             ByteArrayOutputStream stdout,
   464 |             ByteArrayOutputStream stderr)
   465 |             throws Exception {
   466 |         Method method =
   467 |                 E2bEnvdProcessClient.class.getDeclaredMethod(
   468 |                         "drainStartStream",
   469 |                         InputStream.class,
   470 |                         ByteArrayOutputStream.class,
   471 |                         ByteArrayOutputStream.class);
   472 |         method.setAccessible(true);
   473 |         try {
   474 |             return (int)
   475 |                     method.invoke(client, new ByteArrayInputStream(connectFrame), stdout, stderr);
   476 |         } catch (java.lang.reflect.InvocationTargetException e) {
   477 |             Throwable cause = e.getCause();
   478 |             if (cause instanceof Exception) {
   479 |                 throw (Exception) cause;
   480 |             }
   481 |             throw e;
   482 |         }
   483 |     }
