   485 |     private static byte[] envelope(int flags, byte[] payload) {
   486 |         byte[] out = new byte[5 + payload.length];
   487 |         out[0] = (byte) flags;
   488 |         ByteBuffer.wrap(out, 1, 4).order(ByteOrder.BIG_ENDIAN).putInt(payload.length);
   489 |         System.arraycopy(payload, 0, out, 5, payload.length);
   490 |         return out;
   491 |     }
   492 | 
   493 |     private static byte[] connectFrame(String json) {
   494 |         return envelope(0x00, json.getBytes(StandardCharsets.UTF_8));
   495 |     }
   496 | 
   497 |     private static byte[] connectFrame(byte[] payload) {
   498 |         return envelope(0x00, payload);
   499 |     }
   500 | 
   501 |     private static byte[] endStreamFrame(String json) {
   502 |         return envelope(0x02, json.getBytes(StandardCharsets.UTF_8));
   503 |     }
   504 | 
   505 |     private static byte[] concatFrames(byte[]... frames) {
   506 |         ByteArrayOutputStream out = new ByteArrayOutputStream();
   507 |         for (byte[] frame : frames) {
   508 |             out.writeBytes(frame);
   509 |         }
   510 |         return out.toByteArray();
   511 |     }
   512 | 
   513 |     private static byte[] connectFrames(String... jsons) {
   514 |         ByteArrayOutputStream out = new ByteArrayOutputStream();
   515 |         for (String json : jsons) {
   516 |             byte[] frame = connectFrame(json);
   517 |             out.writeBytes(frame);
   518 |         }
   519 |         return out.toByteArray();
   520 |     }
